import{_ as t,o as a,c as s,ae as i}from"./chunks/framework.BIONGpTb.js";const u=JSON.parse('{"title":"Backend Setup and Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"en/backend.md","filePath":"en/backend.md"}'),n={name:"en/backend.md"};function r(o,e,l,c,p,d){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="backend-setup-and-architecture" tabindex="-1">Backend Setup and Architecture <a class="header-anchor" href="#backend-setup-and-architecture" aria-label="Permalink to &quot;Backend Setup and Architecture&quot;">​</a></h1><p>The <strong>Structo</strong> backend is built on <strong>.NET 10</strong> using C#. It follows <strong>Clean Architecture</strong> and <strong>N-Tier</strong> principles to ensure the codebase remains maintainable, testable, and loosely coupled from external technologies.</p><h2 id="🚀-how-to-run-locally" tabindex="-1">🚀 How to Run Locally <a class="header-anchor" href="#🚀-how-to-run-locally" aria-label="Permalink to &quot;🚀 How to Run Locally&quot;">​</a></h2><h3 id="_1-database-preparation" tabindex="-1">1. Database Preparation <a class="header-anchor" href="#_1-database-preparation" aria-label="Permalink to &quot;1. Database Preparation&quot;">​</a></h3><p>Ensure your databases (SQL Server and MongoDB) are running. You can bring up the containers using a <code>docker-compose.yml</code> file (if available in the root or <code>docker/</code> folder):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker-compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><p>Alternatively, use your local instances. Make sure to configure the correct connection strings in the <code>appsettings.Development.json</code> files within the main WebApi project.</p><h3 id="_2-run-migrations-entity-framework" tabindex="-1">2. Run Migrations (Entity Framework) <a class="header-anchor" href="#_2-run-migrations-entity-framework" aria-label="Permalink to &quot;2. Run Migrations (Entity Framework)&quot;">​</a></h3><p>Enter the backend project and apply migrations to the SQL Server database:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ef</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> database</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Structo.Infrastructure/Structo.Infrastructure.csproj</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --startup-project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Structo.WebApi/Structo.WebApi.csproj</span></span></code></pre></div><h3 id="_3-loading-initial-data-seed" tabindex="-1">3. Loading Initial Data (Seed) <a class="header-anchor" href="#_3-loading-initial-data-seed" aria-label="Permalink to &quot;3. Loading Initial Data (Seed)&quot;">​</a></h3><p>To populate the database with base or testing data, the ecosystem usually provides a <em>Seeding</em> mechanism. This is often executed on application startup inside <code>Program.cs</code> configuration, or using a dedicated endpoint.</p><p>If the seed is configured via injection or an integrated endpoint, you typically just need to run the development project and/or trigger the dedicated endpoint (e.g., <code>POST /api/seed</code> from Swagger) to insert the first records.</p><h3 id="_4-run-the-project" tabindex="-1">4. Run the Project <a class="header-anchor" href="#_4-run-the-project" aria-label="Permalink to &quot;4. Run the Project&quot;">​</a></h3><p>Start the Web API by running the following command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Structo.WebApi/Structo.WebApi.csproj</span></span></code></pre></div><p>The development server will initiate (typically exposing a Swagger UI at <code>http://localhost:&lt;port&gt;/swagger</code>).</p><hr><h2 id="🏗️-applied-design-patterns" tabindex="-1">🏗️ Applied Design Patterns <a class="header-anchor" href="#🏗️-applied-design-patterns" aria-label="Permalink to &quot;🏗️ Applied Design Patterns&quot;">​</a></h2><p>During the backend development, the following architectural patterns are actively promoted:</p><ul><li><strong>Dependency Injection (DI)</strong>: Natively used within .NET Core to inject services into controllers and other layers, promoting low coupling.</li><li><strong>Repository Pattern</strong>: Data access abstraction provided by interfaces inside the <code>Domain</code> and physically implemented in the <code>Infrastructure</code> layer.</li><li><strong>Data Transfer Objects (DTO)</strong>: Completely isolating the controller responses from mapping directly to domain models.</li><li><strong>CQRS (Optional, based on complexity)</strong>: Lightweight separation between reads and mutations handled gracefully in the services layer.</li></ul><h2 id="📁-project-structure-n-tier" tabindex="-1">📁 Project Structure (N-Tier) <a class="header-anchor" href="#📁-project-structure-n-tier" aria-label="Permalink to &quot;📁 Project Structure (N-Tier)&quot;">​</a></h2><p>The solution (<code>Structo.sln</code>) and the <code>src/</code> directory are conceptually split into class libraries:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    API[Structo.WebApi\\nPresentation Layer] --&gt; S[Structo.Services\\nApplication Logic]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    API --&gt; DTO[Structo.DTO\\nData Contracts]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; DOM[Structo.Domain\\nBusiness Rules / Entities]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; INF[Structo.Infrastructure\\nData Access / EF Core]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    INF --&gt; DOM</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    API -. Injects .-&gt; INF</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style API fill:#2a70d9,stroke:#333,stroke-width:2px,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style S fill:#0b8a4f,stroke:#333,stroke-width:2px,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style INF fill:#d9702a,stroke:#333,stroke-width:2px,color:#fff</span></span></code></pre></div><h3 id="layer-descriptions" tabindex="-1">Layer Descriptions <a class="header-anchor" href="#layer-descriptions" aria-label="Permalink to &quot;Layer Descriptions&quot;">​</a></h3><ol><li><strong>Structo.WebApi</strong>: Contains Controllers (HTTP Endpoints), host configuration, and the dependency injection registry (<code>Program.cs</code>). Responsible for handling requests and returning DTOs.</li><li><strong>Structo.Services</strong>: Contains application logic. Coordinates interactions with the database via interfaces, and applies business orchestration mapping Domain Entities to/from DTOs.</li><li><strong>Structo.Domain</strong>: The core of the system. Contains Entities (table models), Enums, core Interfaces, and pure business logic strictness. <strong>It has zero references to any other project in the solution</strong>.</li><li><strong>Structo.Infrastructure</strong>: Contains <code>DbContext</code> classes (Entity Framework), concrete repository implementations, and setups for external databases (SQL Server / MongoDB). Depends on <code>Structo.Domain</code>.</li><li><strong>Structo.DTO</strong>: Contains flat structures that transport the requested data to the boundaries of the API, avoiding directly exposing Domain classes.</li><li><strong>Structo.Common</strong>: Cross-cutting constants, shared custom exceptions, and extension methods utilized across the whole platform.</li></ol>`,26)])])}const g=t(n,[["render",r]]);export{u as __pageData,g as default};
